    var currentMax = 1L
    val newMask = mask | (1 << node)
    for (neighbor <- adj(node)) {
      if ((newMask & (1 << neighbor)) == 0) {
        val res = dfs(neighbor, newMask)
        currentMax = math.max(currentMax, res + 1)
      }
    }

    memo(key) = currentMax
    currentMax
  }

  for (start <- 0 until n.toInt) {
    val pathMask = 1 << start
    val path = dfs(start, 0)
    val pathLabels = new StringBuilder
    var tempMask = pathMask
    var currentNode = start
    pathLabels.append(label(currentNode))
    var remaining = path - 1
    while (remaining > 0) {
      var found = false
      for (neighbor <- adj(currentNode)) {
        if ((tempMask & (1 << neighbor)) == 0 && dfs(neighbor, tempMask) == remaining) {
          pathLabels.append(label(neighbor))
          tempMask |= (1 << neighbor)
          currentNode = neighbor
          remaining -= 1
          found = true
