import scala.collection.mutable.{ArrayBuffer, HashMap}

def solve(n: Long, edges: Array[Array[Long]], label: String): Long = {
    val adj = Array.fill(n.toInt)(ArrayBuffer[Int]())
    for (e <- edges) {
        val u = e(0).toInt
        val v = e(1).toInt
        adj(u) += v
        adj(v) += u
    }

    var maxLen = 1L
    val memo = HashMap[(Int, Int), Long]()

    def dfs(node: Int, mask: Int): Long = {
        val key = (node, mask)
        if (memo.contains(key)) return memo(key)

        var currentMax = 1L
        val newMask = mask | (1 << node)
        for (neighbor <- adj(node)) {
            if ((newMask & (1 << neighbor)) == 0) {
                val res = dfs(neighbor, newMask)
                currentMax = math.max(currentMax, res + 1)
            }
        }

        memo(key) = currentMax
        currentMax
    }

    for (start <- 0 until n.toInt) {
        val pathLen = dfs(start, 0)
        if (pathLen > maxLen) {
            maxLen = pathLen
        }
    }

    def isPalindrome(s: String): Boolean = {
        s == s.reverse
    }

    def generatePaths(): Long = {
        var max = 1L
        for (mask <- 1 until (1 << n.toInt)) {
            val nodes = (0 until n.toInt).filter(i => (mask & (1 << i)) != 0)
            if (nodes.nonEmpty) {
                val s = nodes.map(i => label.charAt(i)).mkString
                if (isPalindrome(s) && s.length > max) {
                    max = s.length
                }
            }
        }
        max
    }

    generatePaths()
}
