        val visited = Array.ofDim[Boolean](n.toInt)
        dfs(start, visited, Map(label(start) -> 1))
    }

    def dfs(node: Int, visited: Array[Boolean], charCount: Map[Char, Int]): Unit = {
        visited(node) = true

        val oddCount = charCount.values.count(_ % 2 == 1)
        if (oddCount <= 1) {
            maxLen = math.max(maxLen, charCount.values.sum)
        }

        for (neighbor <- adj(node) if !visited(neighbor)) {
            val c = label(neighbor)
            val newCount = charCount.updated(c, charCount.getOrElse(c, 0) + 1)
            dfs(neighbor, visited.clone(), newCount)
        }
    }

    maxLen
}
